import React, { useMemo } from 'react';
import { ClanMember, GameState } from '../../../types';
import { getRealmStyle, getRealmText, getTierColor, getGenerationTitle, getGenerationChar, calculateMemberGeneration } from '../Shared/utils';

interface Props {
    member: ClanMember;
    state: GameState;
    onSelectMember: (id: string) => void;
}

const RelationTab: React.FC<Props> = ({ member, state, onSelectMember }) => {
    const findMember = (id?: string | null) => state.members.find(m => m.id === id);

    const father = findMember(member.fatherId);
    const mother = findMember(member.motherId);
    const spouse = findMember(member.spouseId);

    const children = state.members.filter(m => m.fatherId === member.id || m.motherId === member.id);
    const siblings = state.members.filter(m => 
        m.id !== member.id && 
        (m.fatherId === member.fatherId && member.fatherId !== null) &&
        (m.motherId === member.motherId && member.motherId !== null)
    );

    // 动态计算代数
    const generation = useMemo(() => calculateMemberGeneration(member, state.members), [member, state.members]);

    const MemberCard = ({ member: m, label, icon }: { member: ClanMember, label: string, icon: string }) => (
        <div 
            onClick={() => onSelectMember(m.id)}
            className="bg-black/30 border border-yellow-900/20 p-4 rounded-lg flex items-center gap-4 hover:border-yellow-500/50 transition-all cursor-pointer group shadow-lg"
        >
            <div className="w-12 h-12 rounded-full bg-yellow-900/10 flex items-center justify-center border border-yellow-900/30 text-2xl group-hover:scale-110 transition-transform">
                {icon}
            </div>
            <div className="flex-1">
                <div className="flex justify-between items-center">
                    <span className="text-sm sm:text-base font-bold text-yellow-100">{m.name}</span>
                    <span className="text-[10px] sm:text-xs text-gray-500 bg-black/40 px-2 py-0.5 rounded border border-white/5">{label}</span>
                </div>
                <div className="flex justify-between items-center mt-1.5">
                    <span className={`text-[11px] sm:text-xs ${getRealmStyle(m.realm).split(' ')[2]}`}>{getRealmText(m.realm, m.subRealm)}</span>
                    <span className={`text-[11px] sm:text-xs font-black ${getTierColor(m.tier)}`}>{m.tier}</span>
                </div>
            </div>
        </div>
    );

    const genChar = getGenerationChar(generation, member.gender);

    return (
        <div className="h-full overflow-y-auto custom-scrollbar space-y-10 animate-fade-in pr-2 pt-2">
            <div className="bg-black/20 p-6 rounded-xl border border-yellow-900/10 flex items-center justify-between">
                <div>
                    <p className="text-xs sm:text-sm text-gray-500">当前辈分</p>
                    <p className="text-2xl font-cursive text-yellow-500 mt-1">{getGenerationTitle(generation)}</p>
                    {genChar && (
                        <p className="text-xs text-yellow-800/60 font-bold mt-1">排字：【{genChar}】</p>
                    )}
                </div>
                <div className="text-right">
                    <p className="text-xs sm:text-sm text-gray-500">家族职位</p>
                    <p className="text-base sm:text-lg font-bold text-orange-400 mt-1">{member.position}</p>
                </div>
            </div>

            {(father || mother || spouse) && (
                <div className="space-y-4">
                    <h4 className="text-yellow-600 text-sm sm:text-base font-bold uppercase tracking-[0.2em] border-b border-yellow-900/10 pb-2 flex items-center gap-2">💍 至亲眷属</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {father && <MemberCard member={father} label="尊父" icon="👴" />}
                        {mother && <MemberCard member={mother} label="慈母" icon="👵" />}
                        {spouse && <MemberCard member={spouse} label="道侣" icon="💍" />}
                    </div>
                </div>
            )}

            {siblings.length > 0 && (
                <div className="space-y-4">
                    <h4 className="text-yellow-600 text-sm sm:text-base font-bold uppercase tracking-[0.2em] border-b border-yellow-900/10 pb-2 flex items-center gap-2">🤝 同胞兄弟</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {siblings.map(m => <MemberCard key={m.id} member={m} label="同胞" icon="🤝" />)}
                    </div>
                </div>
            )}

            {children.length > 0 && (
                <div className="space-y-4">
                    <h4 className="text-yellow-600 text-sm sm:text-base font-bold uppercase tracking-[0.2em] border-b border-yellow-900/10 pb-2 flex items-center gap-2">👶 膝下子女</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {children.map(m => <MemberCard key={m.id} member={m} label="子女" icon="👶" />)}
                    </div>
                </div>
            )}
        </div>
    );
};

export default RelationTab;
